READING_BY_LANG = {"ru": READING_RU, "kk": READING_KK}
SUBJECTS = list(QUESTIONS_RU.keys())  # канонический список уровней: HSK 1..6
SUBJECTS_KK = list(QUESTIONS_KK.keys())
FREE_SUBJECTS = ["HSK 1"]  # бесплатный план — только HSK 1

def subjects_for_lang(lang):
    if lang == "kk":
        return SUBJECTS_KK
    return SUBJECTS

def subject_to_canonical(subject, lang):
    if lang == "kk" and subject in SUBJECT_MAP_KK_RU:
        return SUBJECT_MAP_KK_RU[subject]
    return subject

def subject_to_display(canonical_subject, lang):
    if lang == "kk":
        return SUBJECT_MAP_RU_KK.get(canonical_subject, canonical_subject)
    return canonical_subject

