def load_users():
    if DATA_FILE.exists():
        with open(DATA_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def save_users(users):
    with open(DATA_FILE, "w", encoding="utf-8") as f:
        json.dump(users, f, ensure_ascii=False, indent=2)

def get_user(users, uid):
    uid = str(uid)
    if uid not in users:
        users[uid] = {
            "name": "",
            "lang": "ru",
            "stats": {s: {"correct": 0, "total": 0} for s in SUBJECTS},
            "asked": {s: [] for s in SUBJECTS},
            "asked_reading": {s: [] for s in SUBJECTS},  # прогресс по вопросам "Чтение" (отдельно от обычных)
            "broadcast": True,
            "plan": "free",
            "plan_until": None,
            "questions_today": 0,
            "last_question_date": "",
            "test_today": 0,
            "last_test_date": "",
            "test_mode": False,
            "test_subject": None,
            "reading_subject": None,  # выбранный уровень для режима "Чтение"
            "pending_payment": None,
            "flashcards": {},        # "HSK 1:0" -> {"interval": 1, "due": "iso-date", "reps": 0, "ease": 2.5}
            "flash_subject": None,   # выбранный уровень для флэшкарт ("all" или конкретный)
            "streak": 0,             # текущая серия дней подряд
            "best_streak": 0,        # лучшая серия за всё время
            "last_activity_date": "",  # дата последнего ответа (для подсчёта streak)
            "today_correct": 0,      # счётчик правильных ответов за сегодня (для вечернего отчёта)
            "today_total": 0,        # счётчик всех ответов за сегодня
            "today_report_date": "",  # дата, на которую считаются today_correct/today_total
            "daily_report_sent_date": "",  # дата последней отправленной вечерней сводки
            "notify_levels": None,   # список уровней для уведомлений, None = все уровни
            "beginner_lesson": 0,    # индекс текущего урока "С нуля" (0 = ещё не начал)
        }
    if "lang" not in users[uid]:
        users[uid]["lang"] = "ru"
    if "flashcards" not in users[uid]:
        users[uid]["flashcards"] = {}
    if "flash_subject" not in users[uid]:
        users[uid]["flash_subject"] = None
    if "asked_reading" not in users[uid]:
        users[uid]["asked_reading"] = {s: [] for s in SUBJECTS}
    if "reading_subject" not in users[uid]:
        users[uid]["reading_subject"] = None
    if "streak" not in users[uid]:
        users[uid]["streak"] = 0
        users[uid]["best_streak"] = 0
        users[uid]["last_activity_date"] = ""
    if "today_correct" not in users[uid]:
        users[uid]["today_correct"] = 0
        users[uid]["today_total"] = 0
        users[uid]["today_report_date"] = ""
        users[uid]["daily_report_sent_date"] = ""
    if "notify_levels" not in users[uid]:
        users[uid]["notify_levels"] = None
    if "beginner_lesson" not in users[uid]:
        users[uid]["beginner_lesson"] = 0
    return users[uid]

def get_lang(user):
    return user.get("lang", "ru")

def is_premium(user):
    if user.get("plan") in ("standard", "premium", "premium_test"):
        until = user.get("plan_until")
        if until and datetime.now() < datetime.fromisoformat(until):
            return True
        user["plan"] = "free"
    return False

def has_test_access(user):
    return is_premium(user) and user.get("plan") == "premium_test"

def reset_daily_if_needed(user):
    today = datetime.now(ALMATY_TZ).strftime("%Y-%m-%d")
    if user.get("last_question_date") != today:
        user["questions_today"] = 0
        user["last_question_date"] = today
    if user.get("last_test_date") != today:
        user["test_today"] = 0
        user["last_test_date"] = today

def register_activity(user, is_correct):
    """Вызывается при КАЖДОМ ответе пользователя в любом режиме.
    Обновляет streak (серию дней подряд) и накопитель для вечернего отчёта."""
    today_str = datetime.now(ALMATY_TZ).strftime("%Y-%m-%d")

    # ── Счётчик за сегодня (для вечерней сводки) ──
    if user.get("today_report_date") != today_str:
        user["today_correct"] = 0
        user["today_total"] = 0
        user["today_report_date"] = today_str
    user["today_total"] = user.get("today_total", 0) + 1
    if is_correct:
        user["today_correct"] = user.get("today_correct", 0) + 1

    # ── Streak (серия дней подряд) ──
    last_date_str = user.get("last_activity_date", "")
    if last_date_str == today_str:
        return  # сегодня уже была активность — streak не меняется повторно

    today_date = datetime.now(ALMATY_TZ).date()
    if last_date_str:
        last_date = datetime.fromisoformat(last_date_str).date()
        gap = (today_date - last_date).days
        if gap == 1:
            user["streak"] = user.get("streak", 0) + 1
        elif gap >= 2:
            user["streak"] = 1  # пропустили день(и) — серия начинается заново
        # gap == 0 невозможен здесь, так как уже проверили last_date_str == today_str выше
    else:
        user["streak"] = 1  # самая первая активность

    user["best_streak"] = max(user.get("best_streak", 0), user["streak"])
    user["last_activity_date"] = today_str

def streak_emoji(streak):
    if streak >= 30:
        return "💎"
    if streak >= 14:
        return "🔥🔥"
    if streak >= 3:
        return "🔥"
    return "✨"

def can_get_question(user):
    reset_daily_if_needed(user)
    plan = user.get("plan", "free") if is_premium(user) else "free"
    limit = PLAN_NOTIFY_LIMIT.get(plan, 1)
    return user["questions_today"] < limit

def can_get_test_question(user):
    reset_daily_if_needed(user)
    return user["test_today"] < TEST_DAILY_LIMIT

def pick_question(user, canonical_subject, lang):
    pool_ru = QUESTIONS_RU[canonical_subject]
    pool_lang = QUESTIONS_BY_LANG[lang][subject_to_display(canonical_subject, lang)] if lang == "kk" else pool_ru
    asked = user["asked"].get(canonical_subject, [])
    available = [i for i in range(len(pool_ru)) if i not in asked]
    if not available:
        user["asked"][canonical_subject] = []
        available = list(range(len(pool_ru)))
    idx = random.choice(available)
    user["asked"][canonical_subject].append(idx)
    return idx, pool_lang[idx]

def pick_reading_question(user, canonical_subject, lang):
    """Как pick_question, но по отдельному банку вопросов на чтение (READING_RU/READING_KK)
    и с отдельным счётчиком asked_reading, чтобы не пересекаться с обычными вопросами."""
    pool_ru = READING_RU[canonical_subject]
    pool_lang = READING_BY_LANG[lang][subject_to_display(canonical_subject, lang)] if lang == "kk" else pool_ru
    if "asked_reading" not in user:
        user["asked_reading"] = {s: [] for s in SUBJECTS}
    asked = user["asked_reading"].get(canonical_subject, [])
    available = [i for i in range(len(pool_ru)) if i not in asked]
    if not available:
        user["asked_reading"][canonical_subject] = []
        available = list(range(len(pool_ru)))
    idx = random.choice(available)
    user["asked_reading"][canonical_subject].append(idx)
    return idx, pool_lang[idx]

# ══════════════════════════════════════════════
# FLASHCARDS — SRS (упрощённый алгоритм SM-2, как в Anki)
# ══════════════════════════════════════════════
def flashcard_key(subject, idx):
    return f"{subject}:{idx}"

def all_flashcard_pairs(subjects):
    """Возвращает список (subject, idx) для всех карточек в указанных уровнях."""
    pairs = []
    for s in subjects:
        for i in range(len(QUESTIONS_RU[s])):
            pairs.append((s, i))
    return pairs

def get_card_state(user, subject, idx):
    key = flashcard_key(subject, idx)
    return user["flashcards"].get(key)

def init_card_state():
    return {"interval": 0, "due": datetime.now(ALMATY_TZ).isoformat(), "reps": 0, "ease": 2.5}

def update_card_state(user, subject, idx, knew_it):
    """Обновляет состояние карточки по упрощённому SM-2: знал -> интервал растёт, не знал -> сброс на 10 минут."""
    key = flashcard_key(subject, idx)
    state = user["flashcards"].get(key, init_card_state())

    if knew_it:
        state["reps"] = state.get("reps", 0) + 1
        ease = state.get("ease", 2.5)
        if state["reps"] == 1:
            interval_days = 1
        elif state["reps"] == 2:
            interval_days = 3
        else:
            interval_days = max(1, round(state.get("interval", 1) * ease))
        state["interval"] = interval_days
        state["ease"] = min(3.0, ease + 0.1)
        due = datetime.now(ALMATY_TZ) + timedelta(days=interval_days)
    else:
        state["reps"] = 0
        state["ease"] = max(1.3, state.get("ease", 2.5) - 0.2)
        state["interval"] = 0
        due = datetime.now(ALMATY_TZ) + timedelta(minutes=10)

    state["due"] = due.isoformat()
    user["flashcards"][key] = state

def pick_flashcard(user, subjects):
    """Выбирает следующую карточку: сначала просроченные (due <= now), иначе новую невиданную карточку."""
    now = datetime.now(ALMATY_TZ)
    pairs = all_flashcard_pairs(subjects)

    due_pairs = []
    new_pairs = []
    for subject, idx in pairs:
        state = get_card_state(user, subject, idx)
        if state is None:
            new_pairs.append((subject, idx))
        else:
            due_dt = datetime.fromisoformat(state["due"])
            if due_dt.tzinfo is None:
                due_dt = ALMATY_TZ.localize(due_dt)
            if due_dt <= now:
                due_pairs.append((subject, idx))

    if due_pairs:
        return random.choice(due_pairs)
    if new_pairs:
        return random.choice(new_pairs)
    # Все карточки выучены и не просрочены — берём случайную для повторения
    return random.choice(pairs) if pairs else (None, None)

def flashcards_progress(user, subjects):
    """Считает сколько карточек выучено (reps>=2) из общего числа в выбранных уровнях."""
    pairs = all_flashcard_pairs(subjects)
    total = len(pairs)
    learned = 0
    for subject, idx in pairs:
        state = get_card_state(user, subject, idx)
        if state and state.get("reps", 0) >= 2:
            learned += 1
    return learned, total

def get_stats_text(user):
    lang = get_lang(user)
    plan_key = user.get("plan", "free") if is_premium(user) else "free"
    plan_label = t(lang, "free_label") if plan_key == "free" else f"⭐️ {PLAN_NAMES[plan_key]}"
    until = ""
    if is_premium(user) and user.get("plan_until"):
        exp = datetime.fromisoformat(user["plan_until"])
        until = f" (до {exp.strftime('%d.%m.%Y')})" if lang == "ru" else f" ({exp.strftime('%d.%m.%Y')} дейін)"
    lines = [t(lang, "stats_title", plan=plan_label, until=until)]
    streak = user.get("streak", 0)
    if streak > 0:
        lines.append(t(lang, "streak_line", emoji=streak_emoji(streak), streak=streak, best=user.get("best_streak", 0)))
        lines.append("")
    total_c, total_t = 0, 0
    for s in SUBJECTS:
        st = user["stats"].get(s, {"correct": 0, "total": 0})
        c, tt = st["correct"], st["total"]
        total_c += c; total_t += tt
        pct = round(c/tt*100) if tt > 0 else 0
        bar = "🟢" * (pct // 20) + "⬜" * (5 - pct // 20)
        display_name = subject_to_display(s, lang)
        lines.append(f"{bar} *{display_name}*: {c}/{tt} ({pct}%)")
    if total_t > 0:
        overall = round(total_c/total_t*100)
        lines.append(t(lang, "stats_total", c=total_c, t=total_t, pct=overall))
        if overall >= 80:
            lines.append(t(lang, "rating_great"))
        elif overall >= 60:
            lines.append(t(lang, "rating_good"))
        else:
            lines.append(t(lang, "rating_more"))
    else:
        lines.append(t(lang, "stats_no_answers"))
    if has_test_access(user):
        reset_daily_if_needed(user)
        lines.append(t(lang, "stats_test_today", today=user["test_today"], limit=TEST_DAILY_LIMIT))
        flash_learned, flash_total = flashcards_progress(user, SUBJECTS)
        lines.append(t(lang, "flashcards_progress", learned=flash_learned, total=flash_total))
    return "\n".join(lines)

