# ОТПРАВКА ВОПРОСА — ОБЫЧНЫЙ РЕЖИМ
# ══════════════════════════════════════════════
async def send_question(bot, chat_id, subject=None):
    users = load_users()
    user = get_user(users, chat_id)
    lang = get_lang(user)

    if not can_get_question(user):
        plan_key = user.get("plan", "free") if is_premium(user) else "free"
        limit = PLAN_NOTIFY_LIMIT.get(plan_key, 1)
        keyboard = [[InlineKeyboardButton(t(lang, "btn_get_premium"), callback_data="show_premium")]]
        await bot.send_message(
            chat_id=chat_id,
            text=t(lang, "limit_reached", limit=limit),
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(keyboard)
        )
        return

    premium = is_premium(user)
    available_subjects = SUBJECTS if premium else FREE_SUBJECTS

    # Если пользователь выбрал конкретные уровни для уведомлений — используем их (с пересечением доступных)
    notify_levels = user.get("notify_levels")
    if notify_levels:
        filtered = [s for s in notify_levels if s in available_subjects]
        if filtered:
            available_subjects = filtered

    if subject is None or subject not in available_subjects:
        subject = random.choice(available_subjects)

    idx, q = pick_question(user, subject, lang)
    user["questions_today"] = user.get("questions_today", 0) + 1
    reset_daily_if_needed(user)
    save_users(users)

    plan_key = user.get("plan", "free") if premium else "free"
    limit = PLAN_NOTIFY_LIMIT.get(plan_key, 1)
    remaining = limit - user["questions_today"]
    display_subject = subject_to_display(subject, lang)

    # Озвучиваем китайскую часть вопроса перед текстом
    await send_audio_for_question(bot, chat_id, q['q'], lang)

    text = f"📚 *{display_subject}*\n\n❓ {q['q']}\n\n" + "\n".join(q["opts"])
    text += f"\n\n_{t(lang, 'remaining')}: {remaining}_"

    keyboard = [[
        InlineKeyboardButton("A", callback_data=f"ans|{chat_id}|{subject}|{idx}|A|notify"),
        InlineKeyboardButton("B", callback_data=f"ans|{chat_id}|{subject}|{idx}|B|notify"),
        InlineKeyboardButton("C", callback_data=f"ans|{chat_id}|{subject}|{idx}|C|notify"),
        InlineKeyboardButton("D", callback_data=f"ans|{chat_id}|{subject}|{idx}|D|notify"),
    ]]
    await bot.send_message(chat_id=chat_id, text=text, parse_mode="Markdown",
                           reply_markup=InlineKeyboardMarkup(keyboard))

