def get_lessons(lang):
    return BEGINNER_LESSONS_KK if lang == "kk" else BEGINNER_LESSONS_RU

async def show_beginner_menu(reply_func, user):
    lang = get_lang(user)
    lessons = get_lessons(lang)
    current = user.get("beginner_lesson", 0)
    total = len(lessons)

    if current >= total:
        progress = t(lang, "beginner_progress_done")
    elif current > 0:
        progress = t(lang, "beginner_progress", current=current, total=total)
    else:
        progress = t(lang, "beginner_progress", current=0, total=total)

    text = t(lang, "beginner_intro", progress=progress)

    if current == 0:
        btn_text = t(lang, "btn_start_lesson", n=1)
        keyboard = [[InlineKeyboardButton(btn_text, callback_data="beginner_lesson|0")]]
    elif current >= total:
        keyboard = [[InlineKeyboardButton(t(lang, "btn_restart_course"), callback_data="beginner_lesson|0")]]
    else:
        btn_text = t(lang, "btn_continue_lesson", n=current + 1)
        keyboard = [[InlineKeyboardButton(btn_text, callback_data=f"beginner_lesson|{current}")]]

    await reply_func(text, parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))

async def send_beginner_lesson(bot, chat_id, lesson_idx):
    users = load_users()
    user = get_user(users, chat_id)
    lang = get_lang(user)
    lessons = get_lessons(lang)

    if lesson_idx >= len(lessons):
        return

    lesson = lessons[lesson_idx]
    text = f"📖 *{lesson['title']}*\n\n{lesson['content']}"

    # Озвучиваем весь китайский текст урока — критично для новичков, которые ещё не умеют читать иероглифы
    chinese_in_lesson = extract_chinese(lesson['content'])
    if chinese_in_lesson:
        audio = generate_audio_bytes(chinese_in_lesson)
        if audio:
            caption = "🎧 Послушай произношение слов из урока" if lang == "ru" else "🎧 Сабақтағы сөздердің айтылымын тыңда"
            try:
                await bot.send_voice(chat_id=chat_id, voice=audio, caption=caption)
            except Exception as e:
                logger.warning(f"Не удалось отправить аудио урока {chat_id}: {e}")

    quiz = lesson.get("quiz")
    if quiz:
        opts_text = "\n".join(quiz["opts"])
        keyboard = [[
            InlineKeyboardButton("A", callback_data=f"beginner_ans|{lesson_idx}|A"),
            InlineKeyboardButton("B", callback_data=f"beginner_ans|{lesson_idx}|B"),
            InlineKeyboardButton("C", callback_data=f"beginner_ans|{lesson_idx}|C"),
            InlineKeyboardButton("D", callback_data=f"beginner_ans|{lesson_idx}|D"),
        ]]
        text += t(lang, "lesson_quiz_intro", q=quiz["q"], opts=opts_text)
        await bot.send_message(chat_id=chat_id, text=text, parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
    else:
        # Последний урок — без квиза, сразу завершение курса
        await bot.send_message(chat_id=chat_id, text=text, parse_mode="Markdown")
        user["beginner_lesson"] = len(lessons)
        save_users(users)


async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    name = update.effective_user.first_name or "Ученик"
    users = load_users()
    user = get_user(users, uid)
    user["name"] = name
    lang = get_lang(user)

    # Проверяем, не потерял ли пользователь серию (пропустил день и ещё не отвечал сегодня)
    streak_lost = False
    today_str = datetime.now(ALMATY_TZ).strftime("%Y-%m-%d")
    last_date_str = user.get("last_activity_date", "")
    if last_date_str and last_date_str != today_str and user.get("streak", 0) > 0:
        last_date = datetime.fromisoformat(last_date_str).date()
        gap = (datetime.now(ALMATY_TZ).date() - last_date).days
        if gap >= 2:
            user["streak"] = 0
            streak_lost = True

    save_users(users)

    if is_premium(user):
        plan_text = t(lang, "plan_premium", plan=PLAN_NAMES[user["plan"]])
    else:
        plan_text = t(lang, "plan_free")

    welcome_text = t(lang, "welcome", name=name, plan_text=plan_text)
    streak = user.get("streak", 0)
    if streak > 0:
        welcome_text += t(lang, "streak_in_welcome", emoji=streak_emoji(streak), streak=streak)
    elif streak_lost:
        welcome_text += "\n\n" + t(lang, "streak_lost_warning")

    await update.message.reply_text(
        welcome_text,
        parse_mode="Markdown",
        reply_markup=main_menu(lang, is_admin=(uid == ADMIN_ID))
    )
    await send_question(context.bot, uid)

