async def show_premium_menu(reply_func, user=None):
    lang = get_lang(user) if user else "ru"
    if user and is_premium(user):
        plan = user.get("plan", "free")
        until = datetime.fromisoformat(user["plan_until"]).strftime("%d.%m.%Y")

        if plan == "premium_test":
            await reply_func(t(lang, "premium_max", until=until), parse_mode="Markdown")
            return

        if plan == "premium":
            keyboard = [[InlineKeyboardButton(t(lang, "btn_upgrade_test"), callback_data="buy_premium_test")]]
            await reply_func(t(lang, "premium_upsell_to_test", until=until), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
            return

        if plan == "standard":
            keyboard = [
                [InlineKeyboardButton(t(lang, "btn_upgrade_premium"), callback_data="buy_premium")],
                [InlineKeyboardButton(t(lang, "btn_upgrade_test"), callback_data="buy_premium_test")],
            ]
            await reply_func(t(lang, "standard_upsell", until=until), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
            return

    keyboard = [
        [InlineKeyboardButton(t(lang, "btn_buy_standard"), callback_data="buy_standard")],
        [InlineKeyboardButton(t(lang, "btn_buy_premium"), callback_data="buy_premium")],
        [InlineKeyboardButton(t(lang, "btn_buy_test"), callback_data="buy_premium_test")],
    ]
    await reply_func(t(lang, "tariffs_full"), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))

# ══════════════════════════════════════════════
# CALLBACK КНОПКИ
# ══════════════════════════════════════════════
async def button_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    data = query.data

    if data.startswith("setlang|"):
        _, new_lang = data.split("|")
        users = load_users()
        user = get_user(users, query.from_user.id)
        user["lang"] = new_lang
        save_users(users)
        await query.message.reply_text(t(new_lang, "lang_set"), reply_markup=main_menu(new_lang, is_admin=(query.from_user.id == ADMIN_ID)))
        return

    if data == "show_premium":
        users = load_users()
        user = get_user(users, query.from_user.id)
        await show_premium_menu(query.message.reply_text, user)
        return

    if data.startswith("test_subject|"):
        _, subject = data.split("|", 1)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        if not has_test_access(user):
            await query.message.reply_text(t(lang, "test_no_access"), parse_mode="Markdown")
            return
        user["test_subject"] = subject
        user["test_mode"] = True
        save_users(users)
        label = t(lang, "all_subjects_label") if subject == "all" else subject_to_display(subject, lang)
        await query.message.reply_text(t(lang, "test_started", label=label), parse_mode="Markdown")
        await send_test_question(context.bot, query.from_user.id)
        return

    if data.startswith("listen_subject|"):
        _, subject = data.split("|", 1)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        if not has_test_access(user):
            await query.message.reply_text(t(lang, "listening_no_access"), parse_mode="Markdown")
            return
        user["test_subject"] = subject
        user["test_mode"] = True
        save_users(users)
        label = t(lang, "all_subjects_label") if subject == "all" else subject_to_display(subject, lang)
        await query.message.reply_text(t(lang, "listening_started", label=label), parse_mode="Markdown")
        await send_listening_question(context.bot, query.from_user.id)
        return

    if data.startswith("reading_subject|"):
        _, subject = data.split("|", 1)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        if not has_test_access(user):
            await query.message.reply_text(t(lang, "reading_no_access"), parse_mode="Markdown")
            return
        user["reading_subject"] = subject
        save_users(users)
        label = t(lang, "all_subjects_label") if subject == "all" else subject_to_display(subject, lang)
        await query.message.reply_text(t(lang, "reading_started", label=label), parse_mode="Markdown")
        await send_reading_question(context.bot, query.from_user.id)
        return

    if data.startswith("showtext|"):
        _, subject, idx = data.split("|")
        idx = int(idx)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        q_display = QUESTIONS_BY_LANG[lang][subject_to_display(subject, lang)][idx] if lang == "kk" else QUESTIONS_RU[subject][idx]
        await query.message.reply_text(f"👁 {q_display['q']}")
        return

    if data.startswith("flash_subject|"):
        _, subject = data.split("|", 1)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        if not has_test_access(user):
            await query.message.reply_text(t(lang, "flashcards_no_access"), parse_mode="Markdown")
            return
        user["flash_subject"] = subject
        save_users(users)
        label = t(lang, "all_subjects_label") if subject == "all" else subject_to_display(subject, lang)
        learned, total = flashcards_progress(user, flash_subjects_list(user))
        await query.message.reply_text(t(lang, "flashcards_started", label=label, learned=learned, total=total), parse_mode="Markdown")
        await send_flashcard_front(context.bot, query.from_user.id)
        return

    if data.startswith("beginner_lesson|"):
        _, idx = data.split("|")
        idx = int(idx)
        await send_beginner_lesson(context.bot, query.from_user.id, idx)
        return

    if data.startswith("beginner_ans|"):
        _, idx, chosen = data.split("|")
        idx = int(idx)
        chat_id = query.from_user.id
        users = load_users()
        user = get_user(users, chat_id)
        lang = get_lang(user)
        lessons = get_lessons(lang)

        if idx >= len(lessons):
            return

        quiz = lessons[idx].get("quiz")
        if quiz:
            is_correct = (chosen == quiz["ans"])
            result = t(lang, "correct", name=(user.get('name') or "Ученик"), ans=quiz["ans"]) if is_correct else t(lang, "incorrect", chosen=chosen, ans=quiz["ans"])
            result += t(lang, "explanation", exp=quiz["exp"])
            await query.edit_message_reply_markup(reply_markup=None)
            await context.bot.send_message(chat_id=chat_id, text=result, parse_mode="Markdown")

        # Отмечаем урок пройденным и регистрируем активность (для streak)
        next_lesson = idx + 1
        user["beginner_lesson"] = max(user.get("beginner_lesson", 0), next_lesson)
        register_activity(user, True)
        save_users(users)

        if next_lesson < len(lessons):
            next_lesson_has_quiz = lessons[next_lesson].get("quiz") is not None
            if next_lesson_has_quiz:
                keyboard = [[InlineKeyboardButton(t(lang, "btn_next_lesson"), callback_data=f"beginner_lesson|{next_lesson}")]]
                await context.bot.send_message(chat_id=chat_id, text=t(lang, "lesson_complete_no_quiz"), reply_markup=InlineKeyboardMarkup(keyboard))
            else:
                # Следующий урок — финальный, без квиза. Отправляем его сразу.
                await context.bot.send_message(chat_id=chat_id, text=t(lang, "lesson_complete_no_quiz"))
                await send_beginner_lesson(context.bot, chat_id, next_lesson)
        return

    if data.startswith("togglelevel|"):
        _, level = data.split("|", 1)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        selected = list(user.get("notify_levels") or [])
        if level in selected:
            selected.remove(level)
        else:
            selected.append(level)
        user["notify_levels"] = selected if selected else None
        save_users(users)

        # Перерисовываем то же сообщение с обновлёнными чекбоксами
        keyboard = []
        for s in SUBJECTS:
            mark = "✅ " if s in selected else "⬜ "
            keyboard.append([InlineKeyboardButton(mark + subject_to_display(s, lang), callback_data=f"togglelevel|{s}")])
        keyboard.append([InlineKeyboardButton(t(lang, "btn_notify_done"), callback_data="notifylevels_done")])
        current = notify_levels_summary(user, lang)
        try:
            await query.edit_message_text(
                t(lang, "notify_levels_intro", current=current),
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(keyboard)
            )
        except Exception:
            pass  # сообщение не изменилось — Telegram иногда выдаёт безобидную ошибку
        return

    if data == "notifylevels_done":
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        levels = user.get("notify_levels")
        if not levels:
            await query.message.reply_text(t(lang, "notify_levels_empty_fallback"))
            levels_text = t(lang, "notify_levels_all")
        else:
            levels_text = ", ".join(subject_to_display(s, lang) for s in levels)
        await query.edit_message_reply_markup(reply_markup=None)
        await query.message.reply_text(t(lang, "notify_levels_saved", levels=levels_text), parse_mode="Markdown")
        return

    if data.startswith("flash_show|"):
        _, subject, idx = data.split("|")
        idx = int(idx)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        q_display = QUESTIONS_BY_LANG[lang][subject_to_display(subject, lang)][idx] if lang == "kk" else QUESTIONS_RU[subject][idx]
        q_ru = QUESTIONS_RU[subject][idx]
        correct_letter = q_ru['ans']
        correct_full_text = next((opt for opt in q_display['opts'] if opt.startswith(correct_letter)), correct_letter)
        display_subject = subject_to_display(subject, lang)

        text = t(lang, "flashcard_back", subject=display_subject, question=q_display['q'], answer=correct_full_text, exp=q_display['exp'])
        keyboard = [[
            InlineKeyboardButton(t(lang, "btn_knew_it"), callback_data=f"flash_rate|{subject}|{idx}|know"),
            InlineKeyboardButton(t(lang, "btn_didnt_know"), callback_data=f"flash_rate|{subject}|{idx}|forgot"),
        ]]
        await query.edit_message_reply_markup(reply_markup=None)
        await context.bot.send_message(chat_id=query.from_user.id, text=text, parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
        return

    if data.startswith("flash_rate|"):
        _, subject, idx, rating = data.split("|")
        idx = int(idx)
        chat_id = query.from_user.id
        users = load_users()
        user = get_user(users, chat_id)
        lang = get_lang(user)

        knew_it = (rating == "know")
        update_card_state(user, subject, idx, knew_it)

        st = user["stats"].setdefault(subject, {"correct": 0, "total": 0})
        st["total"] += 1
        if knew_it:
            st["correct"] += 1
        register_activity(user, knew_it)
        save_users(users)

        key = flashcard_key(subject, idx)
        new_state = user["flashcards"][key]
        if knew_it:
            feedback = t(lang, "flashcard_knew_feedback", interval=new_state["interval"])
        else:
            feedback = t(lang, "flashcard_didnt_know_feedback")

        await query.edit_message_reply_markup(reply_markup=None)
        await context.bot.send_message(chat_id=chat_id, text=feedback)

        # Сразу следующая карточка
        await send_flashcard_front(context.bot, chat_id)
        return

    if data in ("buy_standard", "buy_premium", "buy_premium_test"):
        plan = data.replace("buy_", "")
        price = PLAN_PRICES[plan]
        plan_name = PLAN_NAMES[plan]

        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        user["pending_payment"] = plan
        save_users(users)

        text = t(lang, "payment_text", plan_name=plan_name, price=price, kaspi=KASPI_NUMBER, uid=query.from_user.id)
        keyboard = [[InlineKeyboardButton(t(lang, "btn_paid"), callback_data=f"paid|{plan}|{price}")]]
        await query.message.reply_text(text, parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
        return

    if data.startswith("paid|"):
        _, plan, price = data.split("|")
        uid = query.from_user.id
        raw_name = query.from_user.first_name or "Пользователь"
        safe_name = re.sub(r'[*_`\[\]]', '', raw_name)
        username = f"@{query.from_user.username}" if query.from_user.username else "без юзернейма"
        plan_name = PLAN_NAMES.get(plan, plan)

        users = load_users()
        user = get_user(users, uid)
        lang = get_lang(user)

        admin_text = (
            f"💰 *Новая оплата! (HSK бот)*\n\n"
            f"👤 {safe_name} ({username})\n"
            f"🆔 ID: `{uid}`\n"
            f"📦 Тариф: {plan_name}\n"
            f"💵 Сумма: {price} ₸\n\n"
            f"Подтверди оплату на Kaspi и нажми кнопку 👇"
        )
        admin_keyboard = [[
            InlineKeyboardButton(f"✅ Активировать {plan_name}", callback_data=f"adm_act|{uid}|{plan}")
        ]]
        try:
            await context.bot.send_message(
                chat_id=ADMIN_ID, text=admin_text, parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(admin_keyboard)
            )
        except Exception as e:
            logger.error(f"Не удалось уведомить админа: {e}")
            try:
                plain_text = f"Новая оплата (HSK)!\n\n{safe_name} ({username})\nID: {uid}\nТариф: {plan_name}\nСумма: {price} тг"
                await context.bot.send_message(chat_id=ADMIN_ID, text=plain_text, reply_markup=InlineKeyboardMarkup(admin_keyboard))
            except Exception as e2:
                logger.error(f"Запасной вариант тоже не сработал: {e2}")

        support_keyboard = [[InlineKeyboardButton(t(lang, "btn_support"), url=f"https://t.me/{SUPPORT_USERNAME}")]]
        await query.message.reply_text(
            t(lang, "paid_confirm"), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(support_keyboard)
        )
        return

    if data == "adm_users":
        if query.from_user.id != ADMIN_ID:
            return
        await send_users_list(query.message.reply_text)
        return

    if data == "adm_refresh":
        if query.from_user.id != ADMIN_ID:
            return
        await do_refresh_menu(query.message.reply_text, context.bot)
        return

    if data == "adm_activate_start":
        if query.from_user.id != ADMIN_ID:
            return
        context.user_data["awaiting_activate_id"] = True
        await query.message.reply_text(
            "✏️ Пришли Telegram ID пользователя для активации (просто числом).\n\nНапример: 123456789"
        )
        return

    if data.startswith("adm_act_choose|"):
        if query.from_user.id != ADMIN_ID:
            return
        _, target_uid = data.split("|")
        keyboard = [
            [InlineKeyboardButton("⭐️ Стандарт (790 ₸)", callback_data=f"adm_act|{target_uid}|standard")],
            [InlineKeyboardButton("⭐️ Премиум (990 ₸)", callback_data=f"adm_act|{target_uid}|premium")],
            [InlineKeyboardButton("🧪 Премиум+Тест (1590 ₸)", callback_data=f"adm_act|{target_uid}|premium_test")],
        ]
        await query.message.reply_text(
            f"Выбери тариф для активации пользователю `{target_uid}` 👇",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(keyboard)
        )
        return

    if data.startswith("adm_act|"):
        if query.from_user.id != ADMIN_ID:
            return
        _, target_uid, plan = data.split("|")
        users = load_users()
        user = get_user(users, target_uid)
        user["plan"] = plan
        user["plan_until"] = (datetime.now() + timedelta(days=30)).isoformat()
        user["pending_payment"] = None
        save_users(users)
        plan_name = PLAN_NAMES[plan]
        exp_date = (datetime.now() + timedelta(days=30)).strftime("%d.%m.%Y")
        target_lang = get_lang(user)

        extra = t(target_lang, "activated_extra_test") if plan == "premium_test" else ""
        notice = t(target_lang, "activated", plan_name=plan_name, exp_date=exp_date, extra=extra)
        try:
            await context.bot.send_message(
                chat_id=int(target_uid), text=notice, parse_mode="Markdown", reply_markup=main_menu(target_lang)
            )
            await query.edit_message_text(f"✅ Активировано: {plan_name} для {target_uid} до {exp_date}\n(клиент уведомлён)")
        except Exception as e:
            await query.edit_message_text(f"✅ Активировано: {plan_name} до {exp_date}\n❌ Клиент не уведомлён: {e}")
        return

    if data.startswith("ans|"):
        parts = data.split("|")
        if len(parts) < 6:
            return
        _, chat_id, subject, idx, chosen, mode = parts
        idx = int(idx); chat_id = int(chat_id)
        users = load_users()
        user = get_user(users, chat_id)
        lang = get_lang(user)

        if mode == "reading":
            q_ru = READING_RU[subject][idx]
            q_display = READING_BY_LANG[lang][subject_to_display(subject, lang)][idx] if lang == "kk" else q_ru
        else:
            q_ru = QUESTIONS_RU[subject][idx]
            q_display = QUESTIONS_BY_LANG[lang][subject_to_display(subject, lang)][idx] if lang == "kk" else q_ru
        is_correct = chosen == q_ru["ans"]

        st = user["stats"].setdefault(subject, {"correct": 0, "total": 0})
        st["total"] += 1
        if is_correct:
            st["correct"] += 1
        register_activity(user, is_correct)
        save_users(users)

        display_subject = subject_to_display(subject, lang)
        correct_letter = q_ru['ans']
        correct_full_text = next((opt for opt in q_display['opts'] if opt.startswith(correct_letter)), correct_letter)
        safe_user_name = user.get('name') or ("Ученик" if lang == "ru" else "Оқушы")
        result = t(lang, "correct", name=safe_user_name, ans=correct_full_text) if is_correct else t(lang, "incorrect", chosen=chosen, ans=correct_full_text)
        result += t(lang, "explanation", exp=q_display['exp'])
        result += f"\n\n📊 {display_subject}: {st['correct']}/{st['total']}"
        await query.edit_message_reply_markup(reply_markup=None)
        await context.bot.send_message(chat_id=chat_id, text=result, parse_mode="Markdown")

        if mode == "test":
            users = load_users()
            user = get_user(users, chat_id)
            if has_test_access(user) and can_get_test_question(user):
                await send_test_question(context.bot, chat_id)
            elif has_test_access(user):
                lang2 = get_lang(user)
                await context.bot.send_message(chat_id=chat_id, text=t(lang2, "test_finished", limit=TEST_DAILY_LIMIT))

        elif mode == "listen":
            users = load_users()
            user = get_user(users, chat_id)
            if has_test_access(user) and can_get_test_question(user):
                await send_listening_question(context.bot, chat_id)
            elif has_test_access(user):
                lang2 = get_lang(user)
                await context.bot.send_message(chat_id=chat_id, text=t(lang2, "test_finished", limit=TEST_DAILY_LIMIT))

        elif mode == "reading":
            users = load_users()
            user = get_user(users, chat_id)
            if has_test_access(user) and can_get_test_question(user):
                await send_reading_question(context.bot, chat_id)
            elif has_test_access(user):
                lang2 = get_lang(user)
                await context.bot.send_message(chat_id=chat_id, text=t(lang2, "test_finished", limit=TEST_DAILY_LIMIT))


