async def activate_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        await update.message.reply_text(f"Нет доступа. Твой ID: {update.effective_user.id}")
        return
    args = context.args
    if len(args) < 2:
        await update.message.reply_text("Использование: /activate [user_id] [standard|premium|premium_test]")
        return
    target_uid, plan = args[0], args[1]
    if plan not in ("standard", "premium", "premium_test"):
        await update.message.reply_text("План: standard, premium или premium_test")
        return
    users = load_users()
    user = get_user(users, target_uid)
    user["plan"] = plan
    user["plan_until"] = (datetime.now() + timedelta(days=30)).isoformat()
    user["pending_payment"] = None
    save_users(users)
    plan_name = PLAN_NAMES[plan]
    exp_date = (datetime.now() + timedelta(days=30)).strftime("%d.%m.%Y")
    target_lang = get_lang(user)

    extra = t(target_lang, "activated_extra_test") if plan == "premium_test" else ""
    notice = t(target_lang, "activated", plan_name=plan_name, exp_date=exp_date, extra=extra)
    try:
        await context.bot.send_message(
            chat_id=int(target_uid), text=notice, parse_mode="Markdown", reply_markup=main_menu(target_lang)
        )
        await update.message.reply_text(f"✅ Активировано и отправлено: {plan_name} для {target_uid} до {exp_date}")
    except Exception as e:
        await update.message.reply_text(f"✅ Активировано: {plan_name} до {exp_date}\n❌ Сообщение не дошло: {e}")

async def users_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    await send_users_list(update.message.reply_text)

async def send_users_list(reply_func):
    users = load_users()
    premium_count = sum(1 for u in users.values() if is_premium(u))
    lines = [f"👥 *Всего: {len(users)} | ⭐️ Премиум: {premium_count} | 🆓 Бесплатных: {len(users)-premium_count}*\n"]
    for uid, u in users.items():
        lang_flag = "🇰🇿" if u.get("lang") == "kk" else "🇷🇺"
        if is_premium(u):
            until = datetime.fromisoformat(u["plan_until"]).strftime("%d.%m")
            plan_label = PLAN_NAMES.get(u.get("plan"), u.get("plan"))
            lines.append(f"⭐️{lang_flag} {u.get('name','?')} `{uid}` — {plan_label} до {until}")
        else:
            lines.append(f"🆓{lang_flag} {u.get('name','?')} `{uid}`")
    await reply_func("\n".join(lines), parse_mode="Markdown")

async def refresh_menu_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    await do_refresh_menu(update.message.reply_text, context.bot)

async def do_refresh_menu(reply_func, bot):
    users = load_users()
    sent, failed = 0, 0
    await reply_func(f"🔄 Обновляю меню у {len(users)} пользователей...")
    for uid, u in users.items():
        try:
            lang = get_lang(u)
            text = "🔄 Меню обновлено!" if lang == "ru" else "🔄 Мәзір жаңартылды!"
            await bot.send_message(chat_id=int(uid), text=text, parse_mode="Markdown", reply_markup=main_menu(lang))
            sent += 1
            await asyncio.sleep(0.3)
        except Exception as e:
            failed += 1
            logger.warning(f"Не удалось обновить меню {uid}: {e}")
    await reply_func(f"✅ Готово! Отправлено: {sent}, ошибок: {failed}")

